import os

from stable_baselines3 import TD3
from stable_baselines3.common.noise import NormalActionNoise
from stable_baselines3.common.vec_env import DummyVecEnv
from stable_baselines3.common.callbacks import CheckpointCallback, EvalCallback, CallbackList

# -----------------------------------------------------------------------------
# 0. 共通設定
#    実験で使用する環境IDを指定します
# -----------------------------------------------------------------------------
env_id = "BipedalWalker-v3"

# -----------------------------------------------------------------------------
# 1. TD3版環境の作成
#    BipedalWalker-v3環境を単一で生成し、評価用環境をDummyVecEnvでラップしています
# -----------------------------------------------------------------------------
env_td3 = gym.make(env_id, render_mode="rgb_array")
eval_env_td3 = DummyVecEnv([lambda: gym.make(env_id, render_mode="rgb_array")])

# Define n_actions based on the environment's action space
n_actions = env_td3.action_space.shape[-1]

# -----------------------------------------------------------------------------
# 2. TD3用コールバック設定
#    学習途中のチェックポイント保存と定期評価のためのコールバックを構成します
# -----------------------------------------------------------------------------
td3_ckpt = CheckpointCallback(
    save_freq=1000,               # 何ステップごとにモデルを保存するか
    save_path="./td3_logs_bipedalwalker/",      # Updated model save path
    name_prefix="td3_model"       # 保存ファイル名のプレフィックス
)
td3_eval = EvalCallback(
    eval_env_td3,                                     # 評価用環境
    best_model_save_path="./td3_logs_bipedalwalker/best_model",     # Updated best model save path
    log_path="./td3_logs_bipedalwalker/results",                    # Updated log path
    eval_freq=500,                                     # 何ステップごとに評価を実行するか
    deterministic=True,                                # 評価中は確定的な方策を使用
    render=False                                       # 評価中のレンダリング有無
)
td3_callbacks = CallbackList([td3_ckpt, td3_eval])

# -----------------------------------------------------------------------------
# 3. アクションノイズの設定
#    探索のために平均0、標準偏差0.1の正規分布ノイズを追加します
# -----------------------------------------------------------------------------
td3_noise = NormalActionNoise(mean=np.zeros(n_actions), sigma=0.1 * np.ones(n_actions))

# -----------------------------------------------------------------------------
# 4. TD3モデルの構築
#    MlpPolicyを用い、割引率や学習率、リプレイバッファサイズなどを設定します
# -----------------------------------------------------------------------------
model_td3 = TD3(
    policy="MlpPolicy",             # Changed from CnnPolicy to MlpPolicy for vector observations
    env=env_td3,                     # 学習環境
    action_noise=td3_noise,          # 探索用のノイズモデル
    gamma=0.99,                      # 割引率
    learning_rate=3e-4,              # 学習率
    buffer_size=100_000,             # リプレイバッファの最大サイズ
    learning_starts=1_000,           # ランダムステップ数後に学習開始
    train_freq=(1, "step"),          # 学習頻度（ステップ単位）
    gradient_steps=1,                # 各学習タイミングでの勾配更新回数
    policy_delay=2,                  # ポリシー更新を遅らせるステップ数
    tensorboard_log='tensorboard/',  # TensorBoardログ保存先
    verbose=1                        # ログ出力レベル
)

# -----------------------------------------------------------------------------
# 5. 学習とモデル保存
#    指定ステップ数だけ学習を実行し、完了後にモデルを保存します
# -----------------------------------------------------------------------------
model_td3.learn(total_timesteps=2000, callback=td3_callbacks)
model_td3.save("td3_bipedalwalker") # Updated model save name

# -----------------------------------------------------------------------------
# 6. 環境のクローズ
#    使用した環境をクローズしてリソースを解放します
# -----------------------------------------------------------------------------
env_td3.close()
eval_env_td3.close()

