"""## **1.4. SAC (Soft Actor-Critic)**

Soft Actor-Critic（SAC）は、近年注目を集めているアクター-クリティック型の強化学習アルゴリズムです。A2C/A3C と同様に「アクター」（方策ネットワーク）と「クリティック」（価値関数ネットワーク）を組み合わせていますが、SAC が特にユニークなのは「エントロピーの最大化」を目的関数に組み込んでいる点です。この仕組みによって、エージェントは単に累積報酬を追求するだけでなく、多様な行動を試すよう促されるため、未知の環境における探索が効率化され、局所最適解に陥りにくくなります。

### **1.4.1. SAC の概要**

SAC は主に三つの要素から構成されます。まずアクター（Actor）ネットワークは確率的なポリシーを学習し、与えられた状態に対して「どのアクションをどの程度の確率で実行すべきか」を示す分布を出力します。この確率的出力によりバリエーションのある行動が取りやすくなり、探索の幅が広がります。次にクリティック（Critic）は、状態価値関数 \(V(s)\) と行動価値関数 \(Q(s,a)\) の両方を同時に学習します。特に \(Q(s,a)\) は「ソフト Q 関数」と呼ばれ、通常の報酬評価に加えてエントロピー項も評価に組み込むことで、よりリスクを許容した行動の価値を正確に見積もります。最後に目的関数に含まれるエントロピーの最大化項は、行動分布のランダム性を維持しつつ報酬獲得も追求する役割を果たします。この三つの要素が相互に作用することで、SAC は高次元かつ連続制御が必要なタスクにおいても安定かつ効率的な学習を実現します。

### **1.4.2. SAC の利点**

SAC の最大の強みは、確率的ポリシーとエントロピー最大化の組み合わせによって非常に高いサンプル効率を得られる点にあります。エージェントは同じデータを何度も再利用するオフポリシー特性を持ちつつ、探索と活用のバランスを自動で調整できるため、少ない相互作用回数で優れたパフォーマンスを達成できます。さらに、目的関数にエントロピー項を含めることで学習中のパラメータ更新が滑らかになり、過度な偏りや不安定な振る舞いを抑制します。このため他手法と比べてハイパーパラメータへの頑健性も高く、初期設定のままでも安定して動作するケースが多いのが特徴です。

### **1.4.3. SAC の実装**

"""

import gymnasium as gym
import numpy as np
import os

from stable_baselines3 import SAC
from stable_baselines3.common.env_util import make_vec_env
from stable_baselines3.common.vec_env import DummyVecEnv, VecFrameStack
from stable_baselines3.common.callbacks import CheckpointCallback, EvalCallback, CallbackList

# -----------------------------------------------------------------------------
# 1. 環境の作成
#    BipedalWalker-v3環境を生成し、SAC用のMlpPolicyがベクトル入力を扱える設定としています
# -----------------------------------------------------------------------------
env_id = "BipedalWalker-v3"
env = gym.make(env_id, render_mode='rgb_array')

# -----------------------------------------------------------------------------
# 2. チェックポイントコールバックの設定
#    学習の途中経過を定期的に ./sac_logs_bipedalwalker/ に保存するよう設定します
# -----------------------------------------------------------------------------
checkpoint_callback = CheckpointCallback(
    save_freq=1000,  # 1000ステップごとにモデルを保存
    save_path='./sac_logs_bipedalwalker/', # Updated log path
    name_prefix='sac_model'
)

# -----------------------------------------------------------------------------
# 3. 評価環境と評価コールバックの設定
#    定期的に別環境で学習済みモデルを評価し、最良モデルを ./sac_logs_bipedalwalker/best_model に保存します
# -----------------------------------------------------------------------------
eval_env = gym.make(env_id, render_mode='rgb_array')
eval_env = DummyVecEnv([lambda: eval_env])
eval_callback = EvalCallback(
    eval_env,
    best_model_save_path='./sac_logs_bipedalwalker/best_model', # Updated best model save path
    log_path='./sac_logs_bipedalwalker/results', # Updated log path
    eval_freq=500,       # 500ステップごとに評価
    deterministic=True,  # 評価時は決定的に行動を選択
    render=False         # 評価中はレンダリングを行いません
)

# -----------------------------------------------------------------------------
# 4. コールバックのまとめ
#    CheckpointとEvalのコールバックをCallbackListで結合します
# -----------------------------------------------------------------------------
callback = CallbackList([checkpoint_callback, eval_callback])

# -----------------------------------------------------------------------------
# 5. SACモデルの構築
#    MlpPolicyによりベクトル入力を扱い、オフポリシーのリプレイバッファや自動エントロピー調整を利用します
# -----------------------------------------------------------------------------
model = SAC(
    'MlpPolicy',            # Changed from CnnPolicy to MlpPolicy for vector observations
    env,                     # 単一環境
    gamma=0.99,              # 割引率
    learning_rate=0.00035,    # 学習率
    buffer_size=100000,      # リプレイバッファサイズ
    learning_starts=3000,    # ランダムステップ後に学習開始
    train_freq=(1, 'step'),  # ステップごとに学習
    gradient_steps=1,        # 各学習タイミングでの勾配更新回数
    ent_coef='auto',         # エントロピー係数を自動調整
    target_update_interval=1,# ターゲットネットワークの更新間隔
    verbose=1,               # ログ出力レベル
    tensorboard_log='tensorboard/' # TensorBoardログ保存先
)

# -----------------------------------------------------------------------------
# 6. 学習の実行
#    合計50,000ステップ学習し、設定済みコールバックを適用します
# -----------------------------------------------------------------------------
model.learn(total_timesteps=50000, callback=callback)

# -----------------------------------------------------------------------------
# 7. モデルの保存
#    学習後の最終モデルを "sac_bipedalwalker" として保存します
# -----------------------------------------------------------------------------
model.save("sac_bipedalwalker") # Updated model save name

# -----------------------------------------------------------------------------
# 8. 環境のクローズ
#    使用したGym環境をクローズしてリソースを解放します
# -----------------------------------------------------------------------------
env.close()
eval_env.close()

import gymnasium as gym
from gym_utils import display_video
from stable_baselines3 import SAC # Added to load SAC agent

# -----------------------------------------------------------------------------
# 1. 動画保存フォルダの設定
#    テスト実行時の動画を保存するディレクトリを指定します
# -----------------------------------------------------------------------------
video_folder = "sac_bipedalwalker_videos_practice" # Updated video folder name

# -----------------------------------------------------------------------------
# 2. 環境の作成
#    BipedalWalker-v3環境をRGB配列モードで生成し、動画記録に備えます
# -----------------------------------------------------------------------------
env_id = "BipedalWalker-v3" # Explicitly setting env_id for consistency
env = gym.make(env_id, render_mode='rgb_array')

# -----------------------------------------------------------------------------
# 3. RecordVideoラッパーの適用
#    RecordVideoで環境インタラクションを指定フォルダに録画し、ログ出力を無効化します
# -----------------------------------------------------------------------------
vnv = gym.wrappers.RecordVideo(
    env,
    video_folder=video_folder,
    disable_logger=True
)

# -----------------------------------------------------------------------------
# 4. 環境の初期リセット
#    ラッパー後の環境を一度リセットして初期観測値を取得します
# -----------------------------------------------------------------------------
obs, info = vnv.reset()

# -----------------------------------------------------------------------------
# 5. エージェントのロード
#    学習済みのSACモデルをロードし、テスト用に設定します
# -----------------------------------------------------------------------------
agent = SAC.load('./sac_logs_bipedalwalker/best_model/best_model') # Updated path to BipedalWalker SAC model

# -----------------------------------------------------------------------------
# 6. テスト実行ループ
#    ロードしたエージェントで環境をステップ実行し、終了またはトランケートでリセット後にループを抜けます
# -----------------------------------------------------------------------------
while True:
    action, _states = agent.predict(obs, deterministic=True)
    obs, rewards, done, truncated, info = vnv.step(action)
    if done or truncated:
        obs, info = vnv.reset()
        break

# -----------------------------------------------------------------------------
# 7. 環境クローズと動画表示
#    環境をクローズした後、保存された動画を表示ユーティリティで再生します
# -----------------------------------------------------------------------------
vnv.close()
display_video(vnv, video_folder)

